'use client';

import { useState, FormEvent, ChangeEvent } from 'react';
import { Upload, FileText, AlertCircle, CheckCircle2, Loader2 } from 'lucide-react';

export default function Home() {
  // State untuk form data
  const [namaLengkap, setNamaLengkap] = useState('');
  const [posisiDilamar, setPosisiDilamar] = useState('');
  const [nomorStr, setNomorStr] = useState('');
  const [email, setEmail] = useState('');
  const [whatsapp, setWhatsapp] = useState('');
  const [fileCv, setFileCv] = useState<File | null>(null);

  // State untuk status pengiriman
  const [loading, setLoading] = useState(false);
  const [sukses, setSukses] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');

  // Handle seleksi file dan validasi format + ukuran
  const handleFileChange = (e: ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      
      // 1. Validasi ukuran file (maksimal 2MB)
      if (selectedFile.size > 2 * 1024 * 1024) {
        setErrorMsg('Ukuran file maksimal 2MB.');
        setFileCv(null);
        return;
      }
      
      // 2. Validasi tipe file (PDF, JPG, JPEG, PNG)
      const allowedTypes = ['application/pdf', 'image/jpeg', 'image/png'];
      if (!allowedTypes.includes(selectedFile.type)) {
        setErrorMsg('Format file harus PDF, JPG, atau PNG.');
        setFileCv(null);
        return;
      }

      setErrorMsg('');
      setFileCv(selectedFile);
    }
  };

  // Handle kirim data form ke API Route internal
  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setErrorMsg('');

    try {
      if (!fileCv) {
        throw new Error('Silakan unggah berkas lamaran Anda terlebih dahulu.');
      }

      // Bungkus semua data ke dalam FormData untuk dikirim ke API Route
      const dataForm = new FormData();
      dataForm.append('namaLengkap', namaLengkap);
      dataForm.append('posisiDilamar', posisiDilamar);
      dataForm.append('nomorStr', nomorStr);
      dataForm.append('email', email);
      dataForm.append('whatsapp', whatsapp);
      dataForm.append('fileCv', fileCv); // File fisik asli

      // TEMBAK KE API ROUTE INTERNAL (Bukan langsung ke Supabase Client)
      const response = await fetch('/api/upload', {
        method: 'POST',
        body: dataForm,
      });

      const result = await response.json();

      if (!response.ok) {
        throw new Error(result.error || 'Terjadi kesalahan saat mengirim data.');
      }

      // Jika sukses, ubah tampilan
      setSukses(true);
    } catch (err: any) {
      setErrorMsg(err.message || 'Terjadi kesalahan saat mengirim data.');
    } finally {
      setLoading(false);
    }
  };

  if (sukses) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4 text-slate-800">
        <div className="bg-white p-8 rounded-2xl shadow-sm max-w-md w-full text-center border border-slate-200/60 animate-in fade-in zoom-in-95 duration-200">
          <div className="bg-emerald-50 text-emerald-600 p-3 rounded-full w-12 h-12 flex items-center justify-center mx-auto mb-4 border border-emerald-100">
            <CheckCircle2 className="w-6 h-6" />
          </div>
          <h2 className="text-xl font-bold text-slate-950">Pendaftaran Berhasil!</h2>
          <p className="text-slate-500 text-sm mt-2">
            Terima kasih telah mendaftar. Data berkas lamaran Anda telah aman tersimpan dalam sistem E-Recruitment RS Arun Lhokseumawe.
          </p>
          <button
            onClick={() => {
              setSukses(false);
              setNamaLengkap('');
              setPosisiDilamar('');
              setNomorStr('');
              setEmail('');
              setWhatsapp('');
              setFileCv(null);
            }}
            className="mt-6 w-full bg-slate-900 hover:bg-slate-800 text-white font-semibold py-2.5 px-4 rounded-xl transition duration-150 text-sm shadow-sm"
          >
            Kirim Lamaran Baru
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 p-4 sm:p-8 flex items-center justify-center">
      <div className="max-w-xl w-full bg-white p-6 sm:p-8 rounded-2xl border border-slate-200/60 shadow-sm space-y-6">
        
        {/* Header Form */}
        <div className="border-b border-slate-100 pb-4">
          <h1 className="text-xl font-bold text-slate-950">Formulir Rekrutmen Online</h1>
          <p className="text-slate-400 text-xs mt-1">RS Arun Lhokseumawe • Silakan isi data dengan benar</p>
        </div>

        {errorMsg && (
          <div className="bg-rose-50 text-rose-600 p-3 rounded-xl flex items-start gap-2 text-xs border border-rose-100">
            <AlertCircle className="w-4 h-4 shrink-0 mt-0.5" />
            <span>{errorMsg}</span>
          </div>
        )}

        {/* Formulir */}
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">Nama Lengkap</label>
            <input
              type="text"
              required
              value={namaLengkap}
              onChange={(e) => setNamaLengkap(e.target.value)}
              placeholder="Masukkan nama lengkap Anda"
              className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:border-emerald-500 transition duration-150"
            />
          </div>

          <div>
            <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">Posisi Yang Dilamar</label>
            <select
              required
              value={posisiDilamar}
              onChange={(e) => setPosisiDilamar(e.target.value)}
              className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:border-emerald-500 transition duration-150 appearance-none"
            >
              <option value="">-- Pilih Posisi --</option>
              <option value="Dokter Umum">Dokter Umum</option>
              <option value="Perawat">Perawat</option>
              <option value="Bidan">Bidan</option>
              <option value="Apoteker">Apoteker</option>
              <option value="Staf IT Support">Staf IT Support</option>
              <option value="Administrasi">Administrasi</option>
            </select>
          </div>

          <div>
            <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">Nomor STR <span className="text-slate-400 font-normal">(Opsional)</span></label>
            <input
              type="text"
              value={nomorStr}
              onChange={(e) => setNomorStr(e.target.value)}
              placeholder="Kosongkan jika tidak ada"
              className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:border-emerald-500 transition duration-150"
            />
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">Email Aktif</label>
              <input
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="contoh@email.com"
                className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:border-emerald-500 transition duration-150"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">Nomor WhatsApp</label>
              <input
                type="tel"
                required
                value={whatsapp}
                onChange={(e) => setWhatsapp(e.target.value)}
                placeholder="Contoh: 08123456789"
                className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:border-emerald-500 transition duration-150"
              />
            </div>
          </div>

          {/* Area Upload File */}
          <div>
            <label className="block text-xs font-semibold uppercase text-slate-500 mb-1.5">Unggah Berkas (CV/Sertifikat)</label>
            <div className="relative border-2 border-dashed border-slate-200 hover:border-emerald-500 bg-slate-50 rounded-2xl p-6 text-center transition duration-150 group">
              <input
                type="file"
                required={!fileCv}
                accept="application/pdf, image/jpeg, image/png"
                onChange={handleFileChange}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
              />
              
              <div className="space-y-2">
                <div className="mx-auto bg-white text-slate-400 group-hover:text-emerald-600 p-2.5 rounded-xl w-10 h-10 flex items-center justify-center border border-slate-200 group-hover:border-emerald-200 transition duration-150 shadow-sm">
                  {fileCv ? <FileText className="w-5 h-5 text-emerald-600" /> : <Upload className="w-5 h-5" />}
                </div>
                
                {fileCv ? (
                  <div>
                    <p className="text-sm font-semibold text-slate-800 line-clamp-1">{fileCv.name}</p>
                    <p className="text-xs text-slate-400 mt-0.5">{(fileCv.size / (1024 * 1024)).toFixed(2)} MB • Klik untuk ganti berkas</p>
                  </div>
                ) : (
                  <div>
                    <p className="text-sm font-medium text-slate-700">Pilih berkas atau seret ke sini</p>
                    <p className="text-xs text-slate-400 mt-0.5">Mendukung PDF, JPG, atau PNG (Maks. 2MB)</p>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Tombol Kirim */}
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-emerald-600 hover:bg-emerald-700 disabled:bg-slate-300 text-white font-semibold py-2.5 px-4 rounded-xl transition duration-150 flex items-center justify-center gap-2 shadow-sm text-sm mt-2"
          >
            {loading ? (
              <>
                <Loader2 className="w-4 h-4 animate-spin" />
                <span>Sedang Mengirim...</span>
              </>
            ) : (
              <span>Kirim Lamaran Sekarang</span>
            )}
          </button>
        </form>
      </div>
    </div>
  );
}